p1:textAppearance="?android:attr/textAppearanceLarge"
p1:id="@+id/txtSomeTextAtTheTop"
p1:layout_width="wrap_content"
p1:layout_height="wrap_content"
p1:layout_gravity="center_horizontal" />
<LinearLayout
p1:orientation="vertical"
p1:minWidth="25px"
p1:minHeight="25px"
p1:layout_width="wrap_content"
p1:layout_height="wrap_content"
