Why does calling setBackgroundColor on a view break its long click color change and highlighting? <p>In Android, by default when you long click on a list item, it goes from the highlight color to white indicating that the user has held it down and a context item will be displayed. Also, you can use the trackball (or arrow buttons on some phones) to select list items rather then using your fingers.</p>
<p>However, I have a ListView whose item's views I am calling setBackgroundColor on, and both of those expected behaviors no longer work. Anybody know why this is and how to fix it?</p>
<p>Notes: Setting the background color in the xml is not an option because I need to be able to set/change the color dynamically.</p>
<p>The code for my newView function is as follows:</p>
<pre><code>@Override
public View newView(Context ctx, Cursor cursor, ViewGroup parent)
{
View view = new View(mCtx);
final LayoutInflater li = (LayoutInflater) mCtx.getSystemService(Context.LAYOUT_INFLATER_SERVICE);
view = li.inflate(R.layout.task_list_item, null);
return view;
}
</code></pre> <p>By default, <code>ListView</code> has a <code>Selector</code> that will play a <code>TransitionDrawable</code> when you longpress a list item. However, if your list item view has a solid background, then you won't be able to see the selector's longpress animation (or on any other states) , because it's covered up by the list item's background.</p>
<p>If you want to see the selector's longpress animation/selected/pressed state, then the list item's has to have a transparent background when the item is selected/pressed/longpressed. You can do it by using a <a href="http://developer.android.com/reference/android/graphics/drawable/StateListDrawable.html">StateListDrawable</a> as your item's background instead of a solid color.</p>
<p>Here is a sample of <a href="http://developer.android.com/reference/android/graphics/drawable/StateListDrawable.html">StateListDrawable</a> for that purpose:</p>
<pre><code>public class ColorfulListItemDrawable extends StateListDrawable {
private final PaintDrawable mColor;
public ColorfulListItemDrawable(int color) {
mColor = new PaintDrawable(color);
initialize();
}
private void initialize() {
Drawable color = mColor;
Drawable selected = new ColorDrawable(Color.TRANSPARENT);
addState(new int[] {android.R.attr.state_pressed, android.R.attr.state_enabled, 
android.R.attr.state_window_focused}, selected);
addState(new int[] {android.R.attr.state_pressed, android.R.attr.state_enabled, 
android.R.attr.state_window_focused,android.R.attr.state_selected}, selected);
addState(new int[] {android.R.attr.state_enabled,android.R.attr.state_window_focused, android.R.attr.state_selected}, selected);
addState(new int[] {}, color);
}
public void setColor(int color) {
mColor.getPaint().setColor(color);
mColor.invalidateSelf();
} 
}
</code></pre>

which the smooth and fast way to load image from net in android list view! <p>i need to list out data from net in that i have 1 image and 2 text. i parse all data and display it but the image displaying very slow in list. so i m looking for best way to do this.</p>
<p>Please help me out.</p>
<p>Thanks In Advance</p> <p>Please copy the below class . That class is download the images from the web and stores into the 
memory card or into internal memory of application .</p>
<pre><code>import java.io.File;
import java.io.FileInputStream;
import java.io.FileNotFoundException;
import java.io.FileOutputStream;
import java.io.InputStream;
import java.io.OutputStream;
import java.net.URL;
import java.util.HashMap;
import java.util.Stack;
import android.app.Activity;
import android.content.Context;
import android.graphics.Bitmap;
import android.graphics.BitmapFactory;
import android.widget.ImageView;
public class Imageloader 
{
// the simplest in-memory cache implementation. This should be replaced with
// something like SoftReference or BitmapOptions.inPurgeable(since 1.6)
private HashMap<String, Bitmap> cache = new HashMap<String, Bitmap>();
private File cacheDir = null;
private Bitmap useThisBitmap = null;
@SuppressWarnings("unused")
private Context ctx = null;
public Imageloader(Context context) 
{
// Make the background thead low priority. This way it will not affect
// the UI performance
ctx = context;
photoLoaderThread.setPriority(Thread.NORM_PRIORITY - 1);
// Find the dir to save cached images
if (android.os.Environment.getExternalStorageState().equals(android.os.Environment.MEDIA_MOUNTED))
cacheDir = new File(android.os.Environment.getExternalStorageDirectory(),"DownloadImages/AlbumArt/");
else
cacheDir = context.getCacheDir();
if (!cacheDir.exists())
cacheDir.mkdirs();
}
public void DisplayImage(String url, Activity activity, ImageView imageView) 
{
if(!url.equals(""))
{
if (cache.containsKey(url))
{
imageView.setImageBitmap(cache.get(url));
}
else
{
queuePhoto(url, activity, imageView);
}
}
}
private void queuePhoto(String url, Activity activity, ImageView imageView) 
{
// This ImageView may be used for other images before. So there may be
// some old tasks in the queue. We need to discard them.
photosQueue.Clean(imageView);
PhotoToLoad p = new PhotoToLoad(url, imageView);
synchronized (photosQueue.photosToLoad) 
{
photosQueue.photosToLoad.push(p);
photosQueue.photosToLoad.notifyAll();
}
// start thread if it's not started yet
if (photoLoaderThread.getState() == Thread.State.NEW)
photoLoaderThread.start();
}
public Bitmap getBitmap(String url) 
{
try
{
// I identify images by hashcode. Not a perfect solution, good for the
// demo.
String filename = String.valueOf(url.hashCode());
File f = new File(cacheDir, filename);
// from SD cache
Bitmap b = decodeFile(f);
if (b != null)
return b;
// from web
try {
Bitmap bitmap = null; 
if(!url.equals("")){
InputStream is = new URL(url).openStream();
OutputStream os = new FileOutputStream(f);
Utils.CopyStream(is, os);
os.close();
bitmap = decodeFile(f);
}
return bitmap;
} 
catch (Exception ex) 
{
ex.printStackTrace();
return null;
}
}
catch(Exception e)
{
e.printStackTrace();
return null; 
}
}
/*decodes image and scales it to reduce memory consumption
* @param file path
* @throws FileNotFoundException
* @return bitmap
* */
private Bitmap decodeFile(File f){
Bitmap b = null;
try {
useThisBitmap = null;
//Decode image size
BitmapFactory.Options o = new BitmapFactory.Options();
o.inJustDecodeBounds = true;
final int IMAGE_MAX_SIZE = 70;
BitmapFactory.decodeStream(new FileInputStream(f), null, o);
int scale = 2;
if (o.outHeight > IMAGE_MAX_SIZE || o.outWidth > IMAGE_MAX_SIZE) {
scale = 2 ^ (int) Math.ceil(Math.log(IMAGE_MAX_SIZE / (double) Math.max(o.outHeight, o.outWidth)) / Math.log(0.5));
}
//Decode with inSampleSize
BitmapFactory.Options o2 = new BitmapFactory.Options();
o2.inSampleSize = scale;
b = BitmapFactory.decodeStream(new FileInputStream(f), null, o2);
useThisBitmap = b;
} 
catch (FileNotFoundException e) {
}
catch(Exception e)
{
e.printStackTrace();
}
finally
{
System.gc();
}
return useThisBitmap;
}
// Task for the queue
private class PhotoToLoad 
{
public String url;
public ImageView imageView;
public PhotoToLoad(String u, ImageView i) {
url = u;
imageView = i;
}
}
private PhotosQueue photosQueue = new PhotosQueue();
// stores list of photos to download
private class PhotosQueue 
{
private Stack<PhotoToLoad> photosToLoad = new Stack<PhotoToLoad>();
// removes all instances of this ImageView
private void Clean(ImageView image) 
{
for (int j = 0; j < photosToLoad.size();) 
{
if (photosToLoad.get(j).imageView == image)
photosToLoad.remove(j);
else
++j;
}
}
}
private class PhotosLoader extends Thread 
{
public void run() 
{
try 
{
while (true) 
{
// thread waits until there are any images to load in the
// queue
if (photosQueue.photosToLoad.size() == 0)
synchronized (photosQueue.photosToLoad) {
photosQueue.photosToLoad.wait();
}
if (photosQueue.photosToLoad.size() != 0) {
PhotoToLoad photoToLoad;
synchronized (photosQueue.photosToLoad) {
photoToLoad = photosQueue.photosToLoad.pop();
}
Bitmap bmp = getBitmap(photoToLoad.url);
cache.put(photoToLoad.url, bmp);
if (((String) photoToLoad.imageView.getTag())
.equals(photoToLoad.url)) {
BitmapDisplayer bd = new BitmapDisplayer(bmp,
photoToLoad.imageView);
Activity a = (Activity) photoToLoad.imageView
.getContext();
a.runOnUiThread(bd);
}
}
if (Thread.interrupted())
break;
}
} catch (InterruptedException e) {
// allow thread to exit
}
}
}
private PhotosLoader photoLoaderThread = new PhotosLoader();
// Used to display bitmap in the UI thread
private class BitmapDisplayer implements Runnable 
{
private Bitmap bitmap;
private ImageView imageView;
private BitmapDisplayer(Bitmap b, ImageView i) 
{
bitmap = b;
imageView = i;
}
public void run() 
{
if (bitmap != null)
imageView.setImageBitmap(bitmap);
}
}
public void stopThread() 
{
photoLoaderThread.interrupt();
}
public void clearCache() 
{
cache.clear();
File[] files = cacheDir.listFiles();
for (File f : files)
f.delete();
}
}
</code></pre>
