mOverlayBtns.draw(gl);
mPass.draw(gl);
}
</code></pre>
<p>The full source can be found on GitHub, <a href="https://github.com/VoteBrian/smoke-or-fire" rel="nofollow">here.</a></p>
<p>Is there something obvious I'm missing? Is there a better way to handle rotating, then rotating back?</p>
<p>So far, I've noticed this problem on:</p>
<ul>
<li>Nexus 4</li>
<li>HTC Sensation</li>
<li>Another LG phone whose name I can't remember</li>
</ul>
<p>These devices do not show the problem:</p>
<ul>
<li>Galaxy Nexus</li>
<li>Nexus 7</li>
<li>Xoom</li>
</ul> <p>I've found a fix for the issue, but I'm still hoping someone will be able to explain the problem I'm seeing above.</p>
<p>Instead of rotating the scene, then rotating back, I can use glPushMatrix and glPopMatrix to isolate the two groups. That way, the group of glTranslate and glRotate to move the scene back are unnecessary.</p>
<pre><code>@Override
public void onDrawFrame(GL10 gl) {
gl.glClear(GL10.GL_COLOR_BUFFER_BIT | GL10.GL_DEPTH_BUFFER_BIT);
gl.glEnableClientState(GL10.GL_VERTEX_ARRAY);
gl.glPushMatrix();
// rotate card table
gl.glRotatef(-20f, 1f, 0f, 0f);
gl.glRotatef( 5f, 0f, 1f, 0f);
gl.glRotatef(-10f, 0f, 0f, 1f);
gl.glTranslatef( 1f, 3f, 0f);
mDeck.draw(gl);
gl.glPopMatrix();
gl.glPushMatrix();
// undo rotate for buttons/overlays
// gl.glTranslatef(-1f, -3f, 0f);
// gl.glRotatef( 10f, 0f, 0f, 1f);
// gl.glRotatef( -5f, 0f, 1f, 0f);
// gl.glRotatef( 20f, 1f, 0f, 0f);
mOverlayBtns.draw(gl);
mPass.draw(gl);
gl.glPopMatrix();
}
</code></pre>

