<pre><code>import java.io.IOException;
import java.net.URL;
import java.util.ArrayList;
import java.util.HashMap;
import org.ksoap2.serialization.SoapObject;
import org.ksoap2.serialization.SoapSerializationEnvelope;
import org.ksoap2.transport.HttpTransportSE;
import org.xmlpull.v1.XmlPullParserException;
import android.app.Activity;
import android.content.Intent;
import android.graphics.Bitmap;
import android.os.Bundle;
import android.view.View;
import android.widget.AdapterView;
import android.widget.AdapterView.OnItemClickListener;
import android.widget.ListView;
import android.widget.TextView;
public class WSDemoFootBallActivity extends Activity {
SoapObject resultinMethod;
TextView tvResult;
URL url;
Bitmap bimage;
ListView list;
LazyAdapter adapter;
static final String TAG_ID = "id";
static final String TAG_NAME = "name";
static final String TAG_COUNTRYNAME = "countryName";
static final String TAG_COUNTRYFLAG = "countryFlag";
private static final String METHOD_NAME = "AllPlayerNames";
private static final String SOAP_ACTION = "";
private static final String NAMESPACE = "http://footballpool.dataaccess.eu";
private static final String URL = "http://footballpool.dataaccess.eu/data/info.wso?WSDL&amp;quot";
//you can get these values from the wsdl file^
/** Called when the activity is first created. */
@Override
public void onCreate(Bundle savedInstanceState) {
super.onCreate(savedInstanceState);
setContentView(R.layout.main);
SoapObject request=new SoapObject(NAMESPACE, METHOD_NAME);
request.addProperty("bSelected", true);
SoapSerializationEnvelope sse=new SoapSerializationEnvelope(SoapSerializationEnvelope.VER11);
sse.setOutputSoapObject(request);
sse.dotNet=true;
HttpTransportSE htse=new HttpTransportSE(URL);
try {
htse.call(SOAP_ACTION, sse);
} catch (IOException e) {
// TODO Auto-generated catch block
e.printStackTrace();
} catch (XmlPullParserException e) {
// TODO Auto-generated catch block
e.printStackTrace();
}
SoapObject res=(SoapObject) sse.bodyIn;
final ArrayList<HashMap<String, String>> valuesList = new ArrayList<HashMap<String, String>>();
for (int i = 0; i < res.getPropertyCount(); i++) {
SoapObject namesObject = (SoapObject) res.getProperty(i);
for(int j=0;j<namesObject.getPropertyCount();j++)
{
Object objectNames=namesObject.getProperty(j);
SoapObject soapObjectIds = (SoapObject)objectNames;
SoapObject soapObjectNames=(SoapObject) objectNames;
SoapObject soapObjectCountryNames = (SoapObject)objectNames;
SoapObject soapObjectCountryFlag = (SoapObject)objectNames;
String id = soapObjectIds.getProperty("iId").toString();
String stringNames=soapObjectNames.getProperty("sName").toString();
String countryName = soapObjectCountryNames.getProperty("sCountryName").toString();
String countryFlag = soapObjectCountryFlag.getProperty("sCountryFlagLarge").toString(); 
// creating new HashMap
HashMap<String, String> map = new HashMap<String, String>();
// adding each child node to HashMap key => value
map.put(TAG_ID, id);
map.put(TAG_NAME, stringNames);
map.put(TAG_COUNTRYNAME, countryName);
map.put(TAG_COUNTRYFLAG, countryFlag);
// adding HashList to ArrayList
valuesList.add(map);
}
}
/**
* Updating parsed JSON data into ListView
* */
// selecting single ListView item
ListView list = (ListView) findViewById(R.id.list);
// Getting adapter by passing xml data ArrayList
adapter=new LazyAdapter(this, valuesList); 
list.setAdapter(adapter);
// Launching new screen on Selecting Single ListItem
list.setOnItemClickListener(new OnItemClickListener() {
@Override
public void onItemClick(AdapterView<?> parent, View view,
int position, long id) {
HashMap<String, String> map = new HashMap<String, String>();
map = valuesList.get(position);
// Starting new intent
Intent in = new Intent(getApplicationContext(), SingleMenuItemActivity.class);
in.putExtra(TAG_ID,map.get(WSDemoFootBallActivity.TAG_ID));
in.putExtra(TAG_NAME,map.get(WSDemoFootBallActivity.TAG_NAME));
in.putExtra(TAG_COUNTRYNAME, map.get(WSDemoFootBallActivity.TAG_COUNTRYNAME));
in.putExtra(TAG_COUNTRYFLAG,map.get(WSDemoFootBallActivity.TAG_COUNTRYFLAG));
startActivity(in);
}
});
}
}
</code></pre>

How to fade out all views when switching activities <p>I have an activity with around 4-5 views on it. It has a white background.
Ideally, I want to fade the entire activity to pure white and then fade in the new activity.
But since color animations are not possible, I've stepped off that idea. The animation that I have made looks like this: </p>
<p>fade-in:</p>
<pre><code><?xml version="1.0" encoding="UTF-8"?>
<set xmlns:android="http://schemas.android.com/apk/res/android">
<alpha android:fromAlpha="0.0" android:toAlpha="1.0" 
android:interpolator="@android:anim/accelerate_interpolator" 
android:duration="1200"/>
</set>
</code></pre>
<p>fade-out:</p>
<pre><code><?xml version="1.0" encoding="UTF-8"?>
<set xmlns:android="http://schemas.android.com/apk/res/android">
<alpha android:fromAlpha="1.0" android:toAlpha="0.0" 
android:interpolator="@android:anim/accelerate_interpolator" 
android:duration="1200"/>
</set>
</code></pre>
<p>I simply set the animation by adding the following line of code to all my activities:</p>
<pre><code>overridePendingTransition( R.animator.fadein, R.animator.fadeout);
</code></pre>
<p>But here's the problem: When fading out using the alpha value of the activity, the entire activity turns to grey when the alpha value is lowered. This does not look pretty with a white background.</p>
<p>So I came up with the idea to just fade out all views on the activity. My question: How do I do this correctly? By the way, if anyone has a better idea, please feel free to tell me. Thanks!</p> <p>I answered my question inspired by the article npace mentioned. You will find my fadeout method below. It uses the animation I already created above to fade out all views that are in the parent container RelativeLayout.</p>
<pre><code>RelativeLayout container = findViewById(R.id.mainContainer);
for(int i = 0; i < container.getChildCount(); i++)
container.getChildAt(i).startAnimation(AnimationUtils.loadAnimation(c, R.animator.fadeout));
new Handler().postDelayed(new Runnable()
{
@Override
public void run()
{
for(int i = 0; i < container.getChildCount(); i++)
container.getChildAt(i).setVisibility(View.INVISIBLE);
c.startActivity(intent);
}
}, fadeDuration);
</code></pre>

