//Here I'm passing progressBar further
}
});
}
</code></pre>
<p>tracklistItem layout:</p>
<pre><code><?xml version="1.0" encoding="utf-8"?>
<FrameLayout xmlns:android="http://schemas.android.com/apk/res/android"
