<p>First thing is NPE came due to you not initialize context object which is you use to inflate layout as well as load image using Picasso so initialize context object in constructor :</p>
<pre><code>this.context= context;
</code></pre>
<p>Second thing is whenever you use custom adapter always try to use <a href="http://developer.android.com/training/improving-layouts/smooth-scrolling.html" rel="nofollow">ViewHolder</a> pattern.</p>
<pre><code>@Override
public View getView(int position, View convertView, ViewGroup parent) {
Viewholder holder;
if (convertView == null) {
holder = new Viewholder();
convertView = LayoutInflater.from(context).inflate(R.layout.item_layout, null);
holder.textView = (TextView) convertView.findViewById(R.id.textView);
holder.menu = (TextView) convertView.findViewById(R.id.menu);
convertView.setTag(holder);
}else{
holder =(Viewholder) convertView.getTag();
}
holder.textView.setText(list.get(position).text);
try {
Picasso.with(context).load(list.get(position).url.toString().replaceAll(" ", "%20")).placeholder(R.drawable.ic_launcher).error(R.drawable.ic_launcher).into(holder.menu);
} catch(IllegalArgumentException illegalArg){
illegalArg.printStackTrace();
} catch(Exception e){
e.printStackTrace();
}
return convertView;
}
class Viewholder {
TextView textView;
ImageView menu;
}
</code></pre>

