<p>Then define custom adapter for your list</p>
<p>public class CustomAdapter extends ArrayAdapter implements View.OnClickListener{</p>
<pre><code>private ArrayList<DataModel> dataSet;
Context mContext;
// View lookup cache
private static class ViewHolder {
TextView title;
TextView description;
TextView addedBy;
Button yourButton;
}
public CustomAdapter(ArrayList<DataModel> data, Context context) {
super(context, R.layout.list_view_items, data);
this.dataSet = data;
this.mContext=context;
}
@Override
public void onClick(View v) {
int position=(Integer) v.getTag();
Object object= getItem(position);
DataModel dataModel=(DataModel)object;
}
private int lastPosition = -1;
@Override
public DataModel getItem(int position) {
return super.getItem(position);
}
@Override
public View getView(int position, View convertView, ViewGroup parent) {
// Get the data item for this position
final DataModel dataModel = getItem(position);
// Check if an existing view is being reused, otherwise inflate the view
ViewHolder viewHolder; // view lookup cache stored in tag
final View result;
if (convertView == null) {
viewHolder = new ViewHolder();
LayoutInflater inflater = LayoutInflater.from(getContext());
convertView = inflater.inflate(R.layout.list_view_items, parent, false);
viewHolder.title = (TextView) convertView.findViewById(R.id.title);
viewHolder.description = (TextView) convertView.findViewById(R.id.description);
viewHolder.addedBy = (TextView) convertView.findViewById(R.id.addedBy);
viewholder.yourButton = (Button) convertView.findViewById(R.id.btn);
result=convertView;
convertView.setTag(viewHolder);
} else {
viewHolder = (ViewHolder) convertView.getTag();
result=convertView;
}
lastPosition = position;
viewHolder.title.setText(dataModel.getTitle());
viewHolder.description.setText(dataModel.getDescription());
viewHolder.addedBy.setText(dataModel.getAddedby());
viewholder.yourButton.setOnClickListener(this);
// Return the completed view to render on screen
return convertView;
}
}
